+    @AsValueClass
+    record BoxedPoint(Integer x, Integer y) implements Comparable<BoxedPoint> {
+        @Override
+        public int compareTo(BoxedPoint o) {
+            int r = Integer.compare(this.x, o.x);
+            return (r != 0) ? r : Integer.compare(this.y, o.y);
+        }
+    }
